class Solution {
public:
    vector<string> findRepeatedDnaSequences(string s) {
        unordered_map<string, int> seen;
        vector<string> res;
        for (int i = 0; i <= s.length() - 10; i++) {
            string t = s.substr(i, 10);
            if (seen[t] == 1) {
                res.push_back(t);
            }
            seen[t]++;
        }
        return res;
    }
};
